mapper.update:
update tbl_bookmark
set folder_id = null
where folder_id = #{folderId}

update tbl_bookmark
set folder_id = #{folderId}
where id = #{id}

mapper.select:
select b.id, b.member_id, b.post_id, b.folder_id, b.created_datetime
from tbl_bookmark b
where b.id = #{id}

select b.id, b.member_id, b.post_id, b.folder_id, b.created_datetime
from tbl_bookmark b
where b.member_id = #{memberId} and b.post_id = #{postId}
